/**
 * AiFeatureTemplate.js
 *
 * These are the ready-to-use code snippets that get injected into every
 * application generated by Extern AI.
 *
 * Architecture:
 * - Firebase (Firestore) is installed from the FIRST response
 * - The AI chat feature calls the Extern AI Cloud Function endpoint
 *   which uses OpenAI GPT-4o-mini (centrally managed — users never need their own key)
 * - All chat history is saved to Firestore
 */

