// ─── 3. AI Service — calls Cloud Function, saves to Firestore ────────────
// Injected as: src/services/aiService.js
export const AI_SERVICE_TEMPLATE = `
import { db } from '../firebase';
import { collection, addDoc, getDocs, query, orderBy, serverTimestamp } from 'firebase/firestore';

// Extern AI centrally-managed AI proxy (OpenAI GPT-4o-mini — no key needed)
const AI_FUNCTION_URL = 'https://api-bkrpnxig4a-uc.a.run.app/api/generated-app';
const APP_ID = import.meta.env.VITE_APP_ID || 'default-app';

const headers = () => ({
  'Content-Type': 'application/json',
  'X-App-Id': APP_ID,
});

// ── Chat with the AI ──────────────────────────────────────────────────────
export async function chat(messages, systemPrompt = '') {
  const res = await fetch(\`\${AI_FUNCTION_URL}/chat\`, {
    method: 'POST',
    headers: headers(),
    body: JSON.stringify({ messages, systemPrompt }),
  });
  const data = await res.json();
  if (res.status === 402) throw { code: 'TOKEN_LIMIT_REACHED', ...data };
  if (!res.ok) throw new Error(data.error || 'AI request failed');

  // Save conversation to Firestore
  try {
    const lastUserMsg = messages[messages.length - 1];
    await addDoc(collection(db, 'chatHistory'), {
      appId: APP_ID,
      userMessage: lastUserMsg?.content || '',
      aiReply: data.reply,
      tokensUsed: data.tokensUsed || 0,
      timestamp: serverTimestamp(),
    });
  } catch (e) {
    // Non-blocking — don't fail the chat if Firestore write fails
    console.warn('[AI] Could not save to Firestore:', e.message);
  }

  return data; // { reply, tokensUsed, tokensTotal, freeLimit }
}

// ── Load chat history from Firestore ─────────────────────────────────────
export async function loadChatHistory(limitCount = 50) {
  try {
    const q = query(
      collection(db, 'chatHistory'),
      orderBy('timestamp', 'desc'),
    );
    const snap = await getDocs(q);
    return snap.docs
      .map(d => d.data())
      .filter(d => d.appId === APP_ID)
      .slice(0, limitCount)
      .reverse();
  } catch (e) {
    console.warn('[AI] Could not load history:', e.message);
    return [];
  }
}

// ── Upload a document for RAG (PDF / plain text) ──────────────────────────
export async function uploadDocument(file) {
  const form = new FormData();
  form.append('file', file);
  const res = await fetch(\`\${AI_FUNCTION_URL}/documents\`, {
    method: 'POST',
    headers: { 'X-App-Id': APP_ID },
    body: form,
  });
  const data = await res.json();
  if (!res.ok) throw new Error(data.error || 'Upload failed');
  return data;
}

// ── Ask a question about uploaded documents (RAG) ─────────────────────────
export async function queryDocuments(question, documentId = null) {
  const res = await fetch(\`\${AI_FUNCTION_URL}/query\`, {
    method: 'POST',
    headers: headers(),
    body: JSON.stringify({ question, documentId }),
  });
  const data = await res.json();
  if (res.status === 402) throw { code: 'TOKEN_LIMIT_REACHED', ...data };
  if (!res.ok) throw new Error(data.error || 'Query failed');
  return data;
}

// ── Fetch current token usage ─────────────────────────────────────────────
export async function getUsage() {
  const res = await fetch(\`\${AI_FUNCTION_URL}/usage\`, { headers: headers() });
  const data = await res.json();
  if (!res.ok) throw new Error(data.error || 'Could not fetch usage');
  return data;
}
`;


// ─── 4. AI Chat UI Component ──────────────────────────────────────────────
// Injected as: src/components/AiChat.jsx
export const AI_CHAT_COMPONENT_TEMPLATE = `
import React, { useState, useRef, useEffect } from 'react';
import { chat, loadChatHistory } from '../services/aiService';

export default function AiChat({ systemPrompt = 'You are a helpful AI assistant.' }) {
  const [messages,  setMessages]  = useState([]);
  const [input,     setInput]     = useState('');
  const [loading,   setLoading]   = useState(false);
  const [error,     setError]     = useState(null);
  const [limitHit,  setLimitHit]  = useState(false);
  const [usage,     setUsage]     = useState(null);
  const bottomRef = useRef(null);

  // Load chat history from Firestore on mount
  useEffect(() => {
    loadChatHistory().then(history => {
      if (history.length > 0) {
        const restored = history.flatMap(h => [
          { role: 'user',      content: h.userMessage },
          { role: 'assistant', content: h.aiReply },
        ]);
        setMessages(restored);
      }
    });
  }, []);

  useEffect(() => { bottomRef.current?.scrollIntoView({ behavior: 'smooth' }); }, [messages]);

  const sendMessage = async () => {
    const text = input.trim();
    if (!text || loading || limitHit) return;

    const userMsg = { role: 'user', content: text };
    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setLoading(true);
    setError(null);

    try {
      const history = [...messages, userMsg].map(m => ({ role: m.role, content: m.content }));
      const result  = await chat(history, systemPrompt);

      setMessages(prev => [...prev, { role: 'assistant', content: result.reply }]);
      setUsage({ tokensUsed: result.tokensTotal, freeLimit: result.freeLimit });
    } catch (err) {
      if (err.code === 'TOKEN_LIMIT_REACHED') {
        setLimitHit(true);
        setError(err.message);
      } else {
        setError(err.message || 'Something went wrong. Please try again.');
      }
    } finally {
      setLoading(false);
    }
  };

  const handleKey = (e) => { if (e.key === 'Enter' && !e.shiftKey) { e.preventDefault(); sendMessage(); } };

  return (
    <div className="ai-chat-container">
      <div className="ai-chat-messages">
        {messages.length === 0 && (
          <div className="ai-chat-empty">
            <span>✨ AI Assistant</span>
            <p>Ask me anything! Your conversations are saved automatically.</p>
          </div>
        )}
        {messages.map((m, i) => (
          <div key={i} className={\`ai-chat-message \${m.role}\`}>
            <span className="ai-chat-role">{m.role === 'user' ? 'You' : 'AI'}</span>
            <p>{m.content}</p>
          </div>
        ))}
        {loading && (
          <div className="ai-chat-message assistant ai-chat-thinking">
            <span className="ai-chat-role">AI</span>
            <p>Thinking…</p>
          </div>
        )}
        <div ref={bottomRef} />
      </div>

      {usage && (
        <div className="ai-usage-bar">
          <div
            className="ai-usage-fill"
            style={{ width: \`\${Math.min(100, (usage.tokensUsed / usage.freeLimit) * 100)}%\` }}
          />
          <span className="ai-usage-label">
            {usage.tokensUsed.toLocaleString()} / {usage.freeLimit.toLocaleString()} free tokens used
          </span>
        </div>
      )}

      {limitHit && (
        <div className="ai-limit-banner">
          <p>🚀 You've used all your free AI tokens.</p>
          <a href="https://externai.com/upgrade" target="_blank" rel="noopener noreferrer">
            Upgrade to Pro — unlimited AI for $9.99/mo
          </a>
        </div>
      )}

      {error && !limitHit && <p className="ai-error">{error}</p>}

      <div className="ai-chat-input-row">
        <textarea
          className="ai-chat-input"
          rows={2}
          value={input}
          onChange={e => setInput(e.target.value)}
          onKeyDown={handleKey}
          placeholder={limitHit ? 'Upgrade to continue chatting…' : 'Type a message…'}
          disabled={loading || limitHit}
        />
        <button
          className="ai-chat-send"
          onClick={sendMessage}
          disabled={loading || limitHit || !input.trim()}
        >
          {loading ? '…' : 'Send'}
        </button>
      </div>
    </div>
  );
}
`;

// ─── 5. Document Upload + RAG Component ───────────────────────────────────
// Injected as: src/components/AiDocSearch.jsx
export const AI_DOC_SEARCH_TEMPLATE = `
import React, { useState } from 'react';
import { uploadDocument, queryDocuments } from '../services/aiService';

export default function AiDocSearch() {
  const [docId,    setDocId]    = useState(null);
  const [fileName, setFileName] = useState('');
  const [question, setQuestion] = useState('');
  const [answer,   setAnswer]   = useState('');
  const [loading,  setLoading]  = useState(false);
  const [status,   setStatus]   = useState('');
  const [limitHit, setLimitHit] = useState(false);

  const handleUpload = async (e) => {
    const file = e.target.files[0];
    if (!file) return;
    setLoading(true);
    setStatus('Indexing document…');
    try {
      const result = await uploadDocument(file);
      setDocId(result.documentId);
      setFileName(result.fileName);
      setStatus(\`✅ "\${result.fileName}" indexed (\${result.chunksIndexed} sections)\`);
    } catch (err) {
      setStatus('❌ Upload failed: ' + err.message);
    } finally {
      setLoading(false);
    }
  };

  const handleQuery = async () => {
    if (!question.trim() || !docId || loading || limitHit) return;
    setLoading(true);
    setAnswer('');
    try {
      const result = await queryDocuments(question, docId);
      setAnswer(result.answer);
    } catch (err) {
      if (err.code === 'TOKEN_LIMIT_REACHED') {
        setLimitHit(true);
        setAnswer(err.message);
      } else {
        setAnswer('Error: ' + err.message);
      }
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="ai-doc-search">
      <h3>📄 Ask Your Documents</h3>
      <label className="ai-upload-btn">
        {loading ? 'Processing…' : fileName ? \`📎 \${fileName}\` : '+ Upload Document'}
        <input type="file" accept=".txt,.md,.csv,.json" onChange={handleUpload} hidden />
      </label>
      {status && <p className="ai-upload-status">{status}</p>}

      {docId && (
        <div className="ai-query-row">
          <input
            className="ai-query-input"
            value={question}
            onChange={e => setQuestion(e.target.value)}
            onKeyDown={e => e.key === 'Enter' && handleQuery()}
            placeholder="Ask a question about your document…"
            disabled={loading || limitHit}
          />
          <button className="ai-query-btn" onClick={handleQuery} disabled={loading || limitHit}>
            {loading ? '…' : 'Ask'}
          </button>
        </div>
      )}
      {answer && <div className="ai-answer"><strong>Answer:</strong> {answer}</div>}
      {limitHit && (
        <a className="ai-upgrade-link" href="https://externai.com/upgrade">
          Upgrade to Pro for unlimited AI →
        </a>
      )}
    </div>
  );
}
`;


export default {
  FIREBASE_INIT_TEMPLATE,
  AI_SERVICE_TEMPLATE,
  AI_CHAT_COMPONENT_TEMPLATE,
  AI_DOC_SEARCH_TEMPLATE,
  ENV_TEMPLATE,
};
